# Write your MySQL query statement below
select t.employee_id, e.name, sum(case when t.rnk = 1 then t.rating else 0 end) - sum(case when t.rnk = 3 then t.rating else 0 end) as improvement_score from (select employee_id, review_date, rating, row_number() over(partition by employee_id order by review_date desc) as rnk from performance_reviews) t left join employees e on t.employee_id = e.employee_id group by employee_id having count(rnk) >= 3 and improvement_score > 0 and sum(case when t.rnk = 1 then t.rating else 0 end) - sum(case when t.rnk = 2 then t.rating else 0 end) > 0 and sum(case when t.rnk = 2 then t.rating else 0 end) - sum(case when t.rnk = 3 then t.rating else 0 end) > 0 order by improvement_score desc, e.name
